<template><section class="page"><van-nav-bar title="交易详情" left-arrow @click-left="router.back()"><template #right><van-icon name="edit" size="20" @click="router.push(`/transactions/${route.params.id}/edit`)" /></template></van-nav-bar><div v-if="loading" class="state-card"><van-loading /></div><van-empty v-else-if="error" image="error" :description="error"><van-button @click="load">重试</van-button></van-empty><template v-else-if="transaction"><van-cell-group inset><van-cell title="日期" :value="transaction.date"/><van-cell title="交易方" :value="transaction.payee || '-'"/><van-cell title="备注" :value="transaction.description || '-'"/><van-cell v-for="posting in transaction.postings" :key="posting.account" :title="posting.account" :value="`${posting.currency} ${posting.amount}`"/></van-cell-group><div style="margin:16px"><van-button block plain type="danger" :loading="deleting" @click="remove">删除交易</van-button></div></template></section></template>
<script setup lang="ts">
import { onMounted, ref } from 'vue'; import { showConfirmDialog } from 'vant'; import { useRoute,useRouter } from 'vue-router'; import { transactionsApi,type Transaction } from '../../api/transactions'; import type { ApiError } from '../../api/client'
const route=useRoute();const router=useRouter();const transaction=ref<Transaction|null>(null);const loading=ref(false);const deleting=ref(false);const error=ref('')
async function load(){loading.value=true;error.value='';try{transaction.value=await transactionsApi.getTransaction(String(route.params.id))}catch(reason){error.value=(reason as ApiError).message}finally{loading.value=false}}
async function remove(){try{await showConfirmDialog({title:'删除交易',message:'确认删除这笔交易？'});deleting.value=true;await transactionsApi.deleteTransaction(String(route.params.id));await router.replace('/transactions')}catch(reason){if((reason as string)!=='cancel'&&typeof reason==='object')error.value=(reason as ApiError).message}finally{deleting.value=false}}
onMounted(load)
</script>
